svg.script:
    
    // 对话数据
    const dialog = [
      { speaker: "王一飞", hanzi: "你在做什么？", pinyin: "Nǐ zài zuò shénme?", en: "What are you doing?" },
      { speaker: "李文", hanzi: "我在学习呢。", pinyin: "Wǒ zài xuéxí ne.", en: "I am studying." },
      { speaker: "王一飞", hanzi: "你学习忙不忙？", pinyin: "Nǐ xuéxí máng bù máng?", en: "Are you busy with your studies?" },
      { speaker: "李文", hanzi: "非常忙，我学医，我们的课很多。", pinyin: "Fēicháng máng, wǒ xué yī, wǒmen de kè hěn duō.", en: "Very busy, I study medicine, we have a lot of classes." },
      { speaker: "王一飞", hanzi: "那你现在要不要和我去超市？", pinyin: "Nà nǐ xiànzài yào bú yào hé wǒ qù chāoshì?", en: "Then do you want to go to the supermarket with me now?" },
      { speaker: "李文", hanzi: "不去，我今天要读一本医学书。", pinyin: "Bú qù, wǒ jīntiān yào dú yì běn yīxué shū.", en: "No, I need to read a medical book today." },
      { speaker: "王一飞", hanzi: "小雪呢？小雪起床没起床？", pinyin: "Xiǎoxuě ne? Xiǎoxuě qǐchuáng méi qǐchuáng?", en: "What about Xiaoxue? Is Xiaoxue up yet?" },
      { speaker: "李文", hanzi: "没起床呢，她还在睡觉。", pinyin: "Méi qǐchuáng ne, tā hái zài shuìjiào.", en: "Not up yet, she is still sleeping." },
      { speaker: "王一飞", hanzi: "好吧，那我一个人去超市。", pinyin: "Hǎo ba, nà wǒ yí gè rén qù chāoshì.", en: "Alright, then I'll go to the supermarket alone." }
    ];

    let currentIndex = 0;
    window.utteranceCache = []; // 修复长文本语音内存被回收的Bug

    const startScreen = document.getElementById('startScreen');
    const speakerTag = document.getElementById('speakerTag');
    const pinyinTag = document.getElementById('pinyin');
    const hanziTag = document.getElementById('hanzi');
    const englishTag = document.getElementById('english');
    const progressBar = document.getElementById('progressBar');
    const voiceIndicator = document.getElementById('voiceIndicator');
    const prevBtn = document.getElementById('prevBtn');
    const nextBtn = document.getElementById('nextBtn');

    // UI 更新函数
    function updateUI() {
      const d = dialog[currentIndex];
      const isMale = d.speaker === "王一飞";
      
      speakerTag.innerHTML = isMale ? "🧔🏻‍♂️ 王一飞 (Wáng Yīfēi)" : "👩🏻‍💼 李文 (Lǐ Wén)";
      speakerTag.style.color = isMale ? "#2980b9" : "#c0392b";
      speakerTag.style.background = isMale ? "#eaf2f8" : "#fdedec";

      pinyinTag.innerText = d.pinyin;
      hanziTag.innerText = d.hanzi;
      englishTag.innerText = d.en;

      progressBar.style.width = ((currentIndex + 1) / dialog.length * 100) + '%';
      
      prevBtn.style.opacity = currentIndex === 0 ? '0.3' : '1';
      nextBtn.style.opacity = currentIndex === dialog.length - 1 ? '0.3' : '1';
    }

    // 智能语音播放函数
    function playAudio() {
      if (!window.speechSynthesis) return;
      window.speechSynthesis.cancel(); 
      
      // 添加 50ms 延迟，防止引擎吞音卡顿
      setTimeout(() => {
          const d = dialog[currentIndex];
          // 将逗号替换为带空格的逗号，强制 TTS 引擎在这里稍微停顿换气，听起来更像真人
          let textToSpeak = d.hanzi.replace(/，/g, "，   ").replace(/。/g, "。 ");
          
          const ut = new SpeechSynthesisUtterance(textToSpeak);
          window.utteranceCache.push(ut); 
          
          ut.lang = 'zh-CN';
          ut.rate = 0.88; // 略微放慢语速，适合外国学生跟读
          
          let voices = window.speechSynthesis.getVoices();
          let zhVoices = voices.filter(v => v.lang.includes('zh') || v.lang.includes('cmn'));
          
          const isMale = (d.speaker === "王一飞");
          let bestVoice = null;
          let isSimulatedMale = false;

          if (zhVoices.length > 0) {
              if (isMale) {
                  // 尝试寻找男声模型 (云希, 云健, 康康 等)
                  bestVoice = zhVoices.find(v => v.name.toLowerCase().match(/(yunxi|yunjian|yunyang|kangkang|lijian|zhiwei)/));
                  
                  // 若无男声包，选用自然女声，并打上“需要变声”的标记
                  if (!bestVoice) {
                      bestVoice = zhVoices.find(v => v.name.includes('Natural') || v.name.includes('Online')) || zhVoices[0];
                      isSimulatedMale = true; 
                  }
              } else {
                  // 寻找女声模型 (晓晓, 婷婷, 晓伊 等)
                  bestVoice = zhVoices.find(v => v.name.toLowerCase().match(/(xiaoxiao|xiaoyi|tingting|yaoyao|huihui|meijia)/));
                  if (!bestVoice) {
                      bestVoice = zhVoices.find(v => v.name.includes('Natural') || v.name.includes('Online')) || zhVoices[0];
                  }
              }
          }

          if (bestVoice) {
              ut.voice = bestVoice;
              if (isSimulatedMale) {
                  // 核心：降调变声处理，完美模拟男声
                  ut.pitch = 0.65; 
                  voiceIndicator.innerText = "⚠️ 电脑未安装男声，已自动对 [" + bestVoice.name + "] 进行降调变声处理模拟男声";
                  voiceIndicator.style.color = "#d35400";
              } else {
                  ut.pitch = 1.0; 
                  voiceIndicator.innerText = "✅ 当前采用的高级发音引擎: " + bestVoice.name;
                  voiceIndicator.style.color = "#FF7E5F";
              }
          } else {
              voiceIndicator.innerText = "⚠️ 无法获取中文语音，请检查系统设置。";
          }

          window.speechSynthesis.speak(ut);
      }, 50);
    }

    // 事件绑定
    startScreen.addEventListener('click', () => {
      startScreen.style.opacity = '0';
      setTimeout(() => { startScreen.style.display = 'none'; }, 400);
      
      // 激活浏览器音频上下文
      let initUt = new SpeechSynthesisUtterance('');
      window.speechSynthesis.speak(initUt);
      
      updateUI();
      setTimeout(playAudio, 400); // 给系统一点加载在线模型的时间
    });

    prevBtn.addEventListener('click', () => {
      if (currentIndex > 0) {
        currentIndex--;
        updateUI();
        playAudio();
      }
    });

    nextBtn.addEventListener('click', () => {
      if (currentIndex < dialog.length - 1) {
        currentIndex++;
        updateUI();
        playAudio();
      }
    });

    document.getElementById('playBtn').addEventListener('click', () => {
      playAudio();
    });

    // 悬停动画效果
    const buttons = [prevBtn, nextBtn, document.getElementById('playBtn')];
    buttons.forEach(btn => {
      btn.addEventListener('mouseover', () => btn.style.transform = 'scale(1.05)');
      btn.addEventListener('mouseout', () => btn.style.transform = 'scale(1)');
      btn.addEventListener('mousedown', () => btn.style.transform = 'scale(0.95)');
      btn.addEventListener('mouseup', () => btn.style.transform = 'scale(1.05)');
    });

    updateUI();
